Prompt Trigger EDM_COMPLETE$AUDIT_TRIG;
CREATE OR REPLACE TRIGGER EDM.EDM_COMPLETE$AUDIT_TRIG
 AFTER INSERT OR UPDATE ON EDM.EDM_COMPLETE FOR EACH ROW
DECLARE 
v_operation VARCHAR2(10) := NULL;
BEGIN
IF INSERTING THEN
   v_operation := 'INS';
ELSIF UPDATING THEN
   v_operation := 'UPD';
END IF;
IF INSERTING OR UPDATING THEN
  INSERT INTO EDM_COMPLETE$TEST_DATA (
    OBJECT_ID, RAW_DATA_ID, BATCH_TYPE_CODE, STUD_REF_NO, BATCH_ID, ENVELOPE_ID, SCAN_DATE, PROC_ERROR, URGENT
    ,aud_action,aud_timestamp,aud_user)  
  VALUES (
    :new.OBJECT_ID, :new.RAW_DATA_ID, :new.BATCH_TYPE_CODE, :new.STUD_REF_NO, :new.BATCH_ID, :new.ENVELOPE_ID, :new.SCAN_DATE, :new.PROC_ERROR, :new.URGENT
    ,v_operation,SYSDATE,USER);
END IF; 
END;
/
SHOW ERRORS;


Prompt Trigger EDM_TEMP$AUDIT_TRIG;
CREATE OR REPLACE TRIGGER EDM.EDM_TEMP$AUDIT_TRIG
 AFTER INSERT OR UPDATE ON EDM.EDM_TEMP FOR EACH ROW
DECLARE 
v_operation VARCHAR2(10) := NULL;
BEGIN
IF INSERTING THEN
   v_operation := 'INS';
ELSIF UPDATING THEN
   v_operation := 'UPD';
END IF;
IF INSERTING OR UPDATING THEN
  INSERT INTO EDM_TEMP$TEST_DATA (
    OBJECT_ID, SESSION_CODE, DOCUMENT_TYPE_CODE, DOCUMENT_NAME, DOCUMENT_TYPE_COUNT, ATTACHMENT_TYPE_CODE, RESCAN_REQUEST_ID
    ,aud_action,aud_timestamp,aud_user)  
  VALUES (
    :new.OBJECT_ID, :new.SESSION_CODE, :new.DOCUMENT_TYPE_CODE, :new.DOCUMENT_NAME, :new.DOCUMENT_TYPE_COUNT, :new.ATTACHMENT_TYPE_CODE, :new.RESCAN_REQUEST_ID
    ,v_operation,SYSDATE,USER);
END IF; 
END;
/
SHOW ERRORS;


