Prompt Trigger EAT_INS;
CREATE OR REPLACE TRIGGER EDM.EAT_INS
BEFORE INSERT
ON EDM.EDM_AUD_TEMP 
FOR EACH ROW
DECLARE
  v_oldval	EDM_AUD_TEMP.OLD%TYPE;
  v_newval	EDM_AUD_TEMP.NEW%TYPE;
  v_date	DATE;
BEGIN
--
  v_oldval := null;
  v_newval := null;
--
-- Get the NEW value from the last audit record for the same field
--
  IF :NEW.action IN ('A', 'B') THEN
    SELECT e1.new
    INTO   v_oldval
    FROM edm_aud_temp e1
    WHERE  e1.raw_data_id = :NEW.raw_data_id
    AND	   e1.field_name = :NEW.field_name
    AND	   e1.aud_date = (SELECT max(e2.aud_date)
                          FROM   edm_aud_temp e2
                          WHERE	 e2.field_name = e1.field_name
                          AND	 e2.raw_Data_id = e1.raw_Data_id);
--
-- Use the value found to populate the OLD value of the new record
--
  :NEW.old := nvl(v_oldval, 'Null');
  v_newval := :NEW.new;
  :NEW.new := nvl(v_newval, 'Null');
--
  END IF;
--
EXCEPTION
  WHEN others THEN
    :NEW.old := 'Null';
  	v_newval := :NEW.new;
    :NEW.new := nvl(v_newval, 'Null');
END wi_ud;
/
SHOW ERRORS;

